[SysClientCacheDataMethodAttribute(true)]
public static display str text(VendTrans _this)
{
    str textVal;

    if(_this.Txt)
    {
        textVal = _this.Txt;
    }
    else if(_this.Txt == "")
    {
        textVal = _this.Invoice;
    }
    return textVal;
}
